    let engine = state.lock().await;
    engine.train_surrogate_model(dataset_path, model_config).await
}

/// Additional types for bridge commands
#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(rename_all = "camelCase")]
pub enum ExportFormat {
    Json,
    Csv,
    Touchstone,
    Matlab,
    Vtu,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(rename_all = "camelCase")]
pub enum ImportFormat {
    Json,
    Stl,
    Step,
    Gerber,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(rename_all = "camelCase")]
pub struct MeshData {
    pub vertices: Vec<Vec3>,
    pub triangles: Vec<[u32; 3]>,
    pub normals: Vec<Vec3>,
    pub edges: Vec<[u32; 2]>,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(rename_all = "camelCase")]
pub struct SurrogateModelConfig {
    pub model_type: String,
    pub input_features: Vec<String>,
    pub output_features: Vec<String>,
    pub hyperparameters: HashMap<String, f64>,
}

/// Trait that the AntennaEngine must implement
#[async_trait::async_trait]
pub trait AntennaEngineInterface {
    async fn create_antenna(&self, params: AntennaParams) -> Result<String>;
    async fn update_antenna(&self, id: String, params: AntennaParams) -> Result<()>;
    async fn delete_antenna(&self, id: String) -> Result<()>;
    async fn start_simulation(&self, antenna_id: String, params: SimulationParams) -> Result<String>;
    async fn get_simulation_progress(&self, simulation_id: String) -> Result<SimulationProgress>;
    async fn get_simulation_results(&self, simulation_id: String) -> Result<SimulationResults>;
    async fn cancel_simulation(&self, simulation_id: String) -> Result<()>;
    async fn start_optimization(&self, config: OptimizationConfig) -> Result<String>;
    async fn get_optimization_progress(&self, optimization_id: String) -> Result<OptimizationProgress>;
    async fn get_optimization_results(&self, optimization_id: String) -> Result<Vec<Solution>>;
    async fn cancel_optimization(&self, optimization_id: String) -> Result<()>;
    async fn export_results(&self, simulation_id: String, format: ExportFormat, path: String) -> Result<()>;
    async fn import_antenna(&self, path: String, format: ImportFormat) -> Result<AntennaParams>;
    async fn get_antenna_mesh(&self, antenna_id: String) -> Result<MeshData>;
    async fn evaluate_surrogate_model(&self, params: AntennaParams) -> Result<SimulationResults>;
    async fn train_surrogate_model(&self, dataset_path: String, model_config: SurrogateModelConfig) -> Result<String>;
}

/**
 * TypeScript interfaces matching Rust antenna types
 */

// Core antenna geometry types
export type AntennaType =
  | { type: 'dipole'; params: DipoleParams }
  | { type: 'patch'; params: PatchParams }
  | { type: 'yagi'; params: YagiParams }
  | { type: 'horn'; params: HornParams }
  | { type: 'custom'; params: CustomGeometry };

export interface DipoleParams {
  length: number;
  radius: number;
  feedGap: number;
  orientation: Vec3;
}

export interface PatchParams {
  width: number;
  length: number;
  substrateHeight: number;
  substratePermittivity: number;
  feedPosition: Vec2;
}

export interface YagiParams {
  drivenElement: DipoleParams;
  reflectorSpacing: number;
  directorSpacings: number[];
  elementLengths: number[];
}

export interface HornParams {
  apertureWidth: number;
  apertureHeight: number;
  length: number;
  waveguideWidth: number;
  waveguideHeight: number;
}

export interface CustomGeometry {
  vertices: Vec3[];
  triangles: [number, number, number][];
  feedEdges: [number, number][];
}

// Material properties
export interface Material {
  name: string;
  permittivity: Complex;
  permeability: Complex;
  conductivity: number;
}

// Antenna parameters for simulation
export interface AntennaParams {
  id: string;
  name: string;
  antennaType: AntennaType;
  material: Material;
  position: Vec3;
  rotation: Vec3;
  meshResolution: MeshResolution;
}

export interface MeshResolution {
  minEdgeLength: number;
  maxEdgeLength: number;
  curvatureRefinement: number;
}

// Optimization types
export interface OptimizationConfig {
  id: string;
  objectives: Objective[];
  constraints: Constraint[];
  variables: DesignVariable[];
  algorithm: OptimizationAlgorithm;
  settings: OptimizationSettings;
}

export interface Objective {
  name: string;
  type: ObjectiveType;
  weight: number;
  targetValue?: number;
}

export type ObjectiveType =
  | 'maximizeGain'
  | 'minimizeReturnLoss'
  | 'maximizeBandwidth'
  | 'minimizeSideLobes'
  | { matchImpedance: Complex }
  | { custom: string };

export interface Constraint {
  name: string;
  type: ConstraintType;
  minValue?: number;
  maxValue?: number;
}

export type ConstraintType =
  | 'dimension'
  | 'gain'
  | 'bandwidth'
  | 'efficiency'
  | 'returnLoss'
  | { custom: string };

export interface DesignVariable {
  name: string;
  path: string;
  minValue: number;
  maxValue: number;
  stepSize?: number;
}

export type OptimizationAlgorithm =
  | { type: 'geneticAlgorithm'; params: GeneticAlgorithmParams }
  | { type: 'particleSwarm'; params: ParticleSwarmParams }
  | { type: 'gradientDescent'; params: GradientDescentParams }
  | { type: 'bayesian'; params: BayesianParams }
  | { type: 'hybrid'; algorithms: OptimizationAlgorithm[] };

export interface GeneticAlgorithmParams {
  populationSize: number;
  mutationRate: number;
  crossoverRate: number;
  eliteSize: number;
}

export interface ParticleSwarmParams {
  particleCount: number;
  inertiaWeight: number;
  cognitiveWeight: number;
  socialWeight: number;
}

export interface GradientDescentParams {
  learningRate: number;
  momentum: number;
  adaptive: boolean;
}

export interface BayesianParams {
  acquisitionFunction: string;
  explorationWeight: number;
  nInitialPoints: number;
}

export interface OptimizationSettings {
  maxIterations: number;
  maxEvaluations: number;
  convergenceTolerance: number;
  parallelEvaluations: number;
  useSurrogateModel: boolean;
  saveHistory: boolean;
}

// Helper types
export interface Vec2 {
  x: number;
  y: number;
}

export interface Vec3 {
  x: number;
  y: number;
  z: number;
}

export interface Complex {
  real: number;
  imag: number;
}

export interface Vec3Complex {
  x: Complex;
  y: Complex;
  z: Complex;
}

// Error types
export type AntennaError =
  | { type: 'invalidGeometry'; message: string }
  | { type: 'simulationFailed'; message: string }
  | { type: 'optimizationFailed'; message: string }
  | { type: 'gpuError'; message: string }
  | { type: 'ioError'; message: string }
  | { type: 'serializationError'; message: string };

// Additional types for UI
export interface MeshData {
  vertices: Vec3[];
  triangles: [number, number, number][];
  normals: Vec3[];
  edges: [number, number][];
}

export type ExportFormat = 'json' | 'csv' | 'touchstone' | 'matlab' | 'vtu';
export type ImportFormat = 'json' | 'stl' | 'step' | 'gerber';

export interface SurrogateModelConfig {
  modelType: string;
  inputFeatures: string[];
  outputFeatures: string[];
  hyperparameters: Record<string, number>;
}

/**
 * TypeScript interfaces for simulation configuration and results
 */

import { Complex, Vec3, Vec3Complex } from './antenna';

// Simulation configuration
export interface SimulationParams {
  frequencyStart: number;
  frequencyStop: number;
  frequencyPoints: number;
  solverType: SolverType;
  boundaryConditions: BoundaryConditions;
  excitation: Excitation;
  convergenceThreshold: number;
  maxIterations: number;
}

export type SolverType =
  | 'methodOfMoments'
  | 'finiteDifference'
  | 'finiteElement'
  | 'hybrid';

export interface BoundaryConditions {
  type: BoundaryType;
  distance: number;
  layers: number;
}

export type BoundaryType =
  | 'perfectlyMatchedLayer'
  | 'absorbingBoundary'
  | 'periodic'
  | 'perfectElectricConductor';

export interface Excitation {
  type: ExcitationType;
  amplitude: number;
  phase: number;
  impedance: number;
}

export type ExcitationType =
  | 'voltageSource'
  | 'currentSource'
  | 'planeWave'
  | 'gaussianBeam';

// Simulation results
export interface SimulationResults {
  id: string;
  antennaId: string;
  timestamp: number;
  frequencies: number[];
  sParameters: SParameters;
  radiationPatterns: RadiationPattern[];
  antennaMetrics: AntennaMetrics;
  currentDistribution?: CurrentDistribution;
  convergenceHistory: number[];
}

export interface SParameters {
  s11: Complex[];
  s21?: Complex[];
  s12?: Complex[];
  s22?: Complex[];
  vswr: number[];
  inputImpedance: Complex[];
}

export interface RadiationPattern {
  frequency: number;
  theta: number[];
  phi: number[];
  eTheta: Complex[][];
  ePhi: Complex[][];
  gain: number[][];
  phase: number[][];
}

export interface AntennaMetrics {
  maxGain: number;
  directivity: number;
  efficiency: number;
  bandwidth: number;
  beamwidthEPlane: number;
  beamwidthHPlane: number;
  frontToBackRatio: number;
  polarization: PolarizationType;
}

export type PolarizationType =
  | { type: 'linear'; angle: number }
  | { type: 'circular'; direction: CircularPolarization }
  | { type: 'elliptical'; majorAxis: number; minorAxis: number };

export type CircularPolarization = 'rightHand' | 'leftHand';

export interface CurrentDistribution {
  meshVertices: Vec3[];
  meshTriangles: [number, number, number][];
  currentDensity: Vec3Complex[];
  magnitude: number[];
  phase: number[];
}

// Progress and status types
export interface SimulationProgress {
  status: SimulationStatus;
  currentFrequency?: number;
  progressPercentage: number;
  estimatedTimeRemaining?: number;
  message: string;
}

export type SimulationStatus =
  | 'idle'
  | 'initializing'
  | 'meshing'
  | 'solving'
  | 'postProcessing'
  | 'completed'
  | { failed: string }
  | 'cancelled';

export interface OptimizationProgress {
  iteration: number;
  bestFitness: number;
  currentFitness: number;
  convergenceMetric: number;
  populationDiversity?: number;
  paretoFront?: Solution[];
}

export interface Solution {
  id: string;
  variables: Record<string, number>;
  objectives: Record<string, number>;
  constraintsSatisfied: boolean;
  simulationResults?: SimulationResults;
}

// Utility functions for working with complex numbers
export const complexMagnitude = (c: Complex): number =>
  Math.sqrt(c.real * c.real + c.imag * c.imag);

export const complexPhase = (c: Complex): number =>
  Math.atan2(c.imag, c.real);

export const complexAdd = (a: Complex, b: Complex): Complex => ({
  real: a.real + b.real,
  imag: a.imag + b.imag,
});

export const complexMultiply = (a: Complex, b: Complex): Complex => ({
  real: a.real * b.real - a.imag * b.imag,
  imag: a.real * b.imag + a.imag * b.real,
});

export const complexToDb = (c: Complex): number =>
  20 * Math.log10(complexMagnitude(c));

export const vswrFromS11 = (s11: Complex): number => {
  const mag = complexMagnitude(s11);
  return (1 + mag) / (1 - mag);
};

// Type guards
export const isSimulationComplete = (
  status: SimulationStatus
): boolean => status === 'completed';

export const isSimulationFailed = (
  status: SimulationStatus
): status is { failed: string } =>
  typeof status === 'object' && 'failed' in status;

export const isCircularPolarization = (
  pol: PolarizationType
): pol is { type: 'circular'; direction: CircularPolarization } =>
  typeof pol === 'object' && pol.type === 'circular';
